const i = items[0].json;
const platform = String(i.platform || '').toLowerCase();
if (!platform) throw new Error('platform is required');
if (!i.file_path) throw new Error('file_path is required');
const tags = typeof i.tags === 'string' && i.tags.trim() ? i.tags.split(',').map(s => s.trim()).filter(Boolean) : (Array.isArray(i.tags) ? i.tags : []);
const body = {
  platform,
  project_id: i.project_id || undefined,
  file_path: i.file_path,
  title: i.title || '',
  description: i.description || '',
  tags,
  visibility: i.visibility || 'private',
  channel_id: i.channel_id || undefined
};
if (i.dry_run !== undefined && i.dry_run !== null && i.dry_run !== '') body.dry_run = Boolean(i.dry_run);
const bodyJson = JSON.stringify(body);
return [{ json: { bodyJson, platform, file_path: i.file_path } }];

const r = items[0].json || {};
const meta = $('Build Body').first().json;
return [{ json: {
  status: r.status || 'error',
  platform: r.platform || meta.platform,
  dry_run: r.dry_run || false,
  id: r.id || null,
  url: r.url || null,
  would_publish: r.would_publish || null,
  error: r.error || null
} }];
